    public DateTime EstimatedDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public double WeightKg { get; set; }
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed,
    Cancelled
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentService
{
    private readonly HttpClient _http;

    public ShipmentService(HttpClient http)
    {
        _http = http;
    }

    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await _http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments") ?? [];
    }

    public async Task<ShipmentDto?> GetByTrackingNumberAsync(string trackingNumber)
    {
        var response = await _http.GetAsync($"api/shipments/track/{Uri.EscapeDataString(trackingNumber)}");
        if (!response.IsSuccessStatusCode)
            return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<ShipmentDto?> UpdateStatusAsync(int id, ShipmentStatus status)
    {
        var response = await _http.PutAsJsonAsync($"api/shipments/{id}/status", status);
        if (!response.IsSuccessStatusCode)
            return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<ShipmentDto?> CreateShipmentAsync(ShipmentDto shipment)
    {
        var response = await _http.PostAsJsonAsync("api/shipments", shipment);
        if (!response.IsSuccessStatusCode)
            return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }
}

