using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Controllers;

[ApiController]
[Route("api/[controller]")]
[Authorize]
public class ShipmentsController : ControllerBase
{
    private readonly ApplicationDbContext _db;

    public ShipmentsController(ApplicationDbContext db)
    {
        _db = db;
    }

    [HttpGet]
    public async Task<ActionResult<List<ShipmentDto>>> GetAll()
    {
        var shipments = await _db.Shipments
            .OrderByDescending(s => s.ShippedDate)
            .Select(s => s.ToDto())
            .ToListAsync();
        return Ok(shipments);
    }

    [HttpGet("track/{trackingNumber}")]
    public async Task<ActionResult<ShipmentDto>> GetByTracking(string trackingNumber)
    {
        var shipment = await _db.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        if (shipment is null)
            return NotFound();
        return Ok(shipment.ToDto());
    }

    [HttpPut("{id}/status")]
    public async Task<ActionResult<ShipmentDto>> UpdateStatus(int id, [FromBody] ShipmentStatus status)
    {
        var shipment = await _db.Shipments.FindAsync(id);
        if (shipment is null)
            return NotFound();

        shipment.Status = status;
        await _db.SaveChangesAsync();
        return Ok(shipment.ToDto());
    }

    [HttpPost]
    public async Task<ActionResult<ShipmentDto>> Create([FromBody] ShipmentDto dto)
    {
        var shipment = Shipment.FromDto(dto);
        shipment.Id = 0;
        if (string.IsNullOrWhiteSpace(shipment.TrackingNumber))
            shipment.TrackingNumber = $"SHP-{Guid.NewGuid().ToString()[..8].ToUpperInvariant()}";

        _db.Shipments.Add(shipment);
        await _db.SaveChangesAsync();
        return CreatedAtAction(nameof(GetByTracking),
            new { trackingNumber = shipment.TrackingNumber }, shipment.ToDto());
    }
}

