                    <input type="number" step="0.1" class="form-control" placeholder="Weight (kg)" @bind="newShipment.WeightKg" />
                </div>
                <div class="col-md-3">
                    <label class="form-label small">Estimated Delivery</label>
                    <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
                </div>
                <div class="col-md-2">
                    <button class="btn btn-success" @onclick="CreateShipment">Create</button>
                    <button class="btn btn-secondary ms-1" @onclick="() => showCreate = false">Cancel</button>
                </div>
            </div>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments match your filter.</p>
}
else
{
    <table class="table table-striped table-hover">
        <thead class="table-dark">
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped</th>
                <th>Est. Delivery</th>
                <th>Customer</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in FilteredShipments)
            {
                <tr>
                    <td><strong>@s.TrackingNumber</strong></td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td>
                        <span class="badge @GetStatusBadge(s.Status)">@s.Status</span>
                    </td>
                    <td>@s.ShippedDate.ToString("MMM dd, yyyy")</td>
                    <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                    <td>@s.CustomerEmail</td>
                    <td>
                        <select class="form-select form-select-sm" style="width:auto;display:inline-block"
                                value="@s.Status"
                                @onchange="e => UpdateStatus(s, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status" selected="@(s.Status == status)">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = "";
    private string filterStatus = "";
    private string? errorMessage;
    private bool showCreate;
    private ShipmentDto newShipment = new() { EstimatedDelivery = DateTime.UtcNow.AddDays(7) };

    private IEnumerable<ShipmentDto> FilteredShipments =>
        (shipments ?? []).Where(s =>
            (string.IsNullOrEmpty(filterText) ||
             s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
             s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase)) &&
            (string.IsNullOrEmpty(filterStatus) ||
             s.Status.ToString() == filterStatus));

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        try
        {
            errorMessage = null;
            shipments = await ShipmentSvc.GetAllShipmentsAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load shipments: {ex.Message}";
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            var updated = await ShipmentSvc.UpdateStatusAsync(shipment.Id, newStatus);
            if (updated is not null)
            {
                shipment.Status = updated.Status;
            }
        }
    }

    private void ShowCreateForm()
    {
        newShipment = new ShipmentDto
        {
            ShippedDate = DateTime.UtcNow,
            EstimatedDelivery = DateTime.UtcNow.AddDays(7)
        };
        showCreate = true;
    }

    private async Task CreateShipment()
    {
        var created = await ShipmentSvc.CreateShipmentAsync(newShipment);
        if (created is not null)
        {
            shipments?.Insert(0, created);
            showCreate = false;
        }
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Cancelled => "bg-dark",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@rendermode InteractiveAuto
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

@inject ShipmentService ShipmentSvc

<PageTitle>Track Shipment</PageTitle>

<h2>🔍 Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" placeholder="Enter tracking number (e.g., SHP-10001)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="Search" disabled="@searching">
                @if (searching)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Search
            </button>
        </div>
    </div>
</div>

@if (errorMessage is not null)
{
    <div class="alert alert-warning">@errorMessage</div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header bg-dark text-white">
            <h4 class="mb-0">Shipment @shipment.TrackingNumber</h4>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl class="row">
                        <dt class="col-sm-5">Status</dt>
                        <dd class="col-sm-7">
                            <span class="badge @GetStatusBadge(shipment.Status) fs-6">@shipment.Status</span>
                        </dd>

                        <dt class="col-sm-5">Description</dt>
                        <dd class="col-sm-7">@shipment.Description</dd>

                        <dt class="col-sm-5">Weight</dt>
                        <dd class="col-sm-7">@shipment.WeightKg kg</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl class="row">
                        <dt class="col-sm-5">Origin</dt>
                        <dd class="col-sm-7">@shipment.Origin</dd>

                        <dt class="col-sm-5">Destination</dt>
                        <dd class="col-sm-7">@shipment.Destination</dd>

                        <dt class="col-sm-5">Shipped Date</dt>
                        <dd class="col-sm-7">@shipment.ShippedDate.ToString("MMMM dd, yyyy")</dd>

                        <dt class="col-sm-5">Estimated Delivery</dt>
                        <dd class="col-sm-7">
                            <strong>@shipment.EstimatedDelivery.ToString("MMMM dd, yyyy")</strong>
                            @if (shipment.EstimatedDelivery > DateTime.UtcNow && shipment.Status != ShipmentStatus.Delivered)
                            {
                                <br />
                                <small class="text-muted">
                                    (~@((shipment.EstimatedDelivery - DateTime.UtcNow).Days) days remaining)
                                </small>
                            }
                            else if (shipment.Status == ShipmentStatus.Delivered)
                            {
                                <br />
                                <small class="text-success">✅ Delivered</small>
                            }
                        </dd>
                    </dl>
                </div>
            </div>

            <h5 class="mt-3">Shipment Progress</h5>
            <div class="progress" style="height: 30px;">
                <div class="progress-bar @GetProgressColor(shipment.Status)"
                     role="progressbar"
                     style="width: @(GetProgress(shipment.Status))%"
                     aria-valuenow="@GetProgress(shipment.Status)"
                     aria-valuemin="0" aria-valuemax="100">
                    @shipment.Status
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = "";
    private ShipmentDto? shipment;
    private string? errorMessage;
    private bool searching;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await Search();
    }

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        searching = true;
        errorMessage = null;
        shipment = null;

        try
        {
            shipment = await ShipmentSvc.GetByTrackingNumberAsync(trackingNumber.Trim());
            if (shipment is null)
                errorMessage = $"No shipment found with tracking number \"{trackingNumber}\".";
        }
        catch (Exception ex)
        {
            errorMessage = $"Error searching: {ex.Message}";
        }
        finally
        {
            searching = false;
        }
    }

    private static int GetProgress(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 55,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };

    private static string GetProgressColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Cancelled => "bg-dark",
        _ => "bg-primary"
    };

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Cancelled => "bg-dark",
        _ => "bg-secondary"
    };
}
